package main
import "fmt"
func main() {
    var A, B int

    fmt.Scan(&A, &B)

    if A > B {
        fmt.Println("invalido")
    } else {
        soma := 0
          for i := A; i <= B; i++ {
            if i%2 == 0 {
                soma += i
            }
          }
          fmt.Println(soma)
    }
}
